// Extract the hostname (Socket ID) from the topic
// Topic structure: telemetry/Socket-XXXXXX/pzem
const topicParts = msg.topic.split('/');
const socketId = topicParts[1];

// Format the data as an array: [{fields}, {tags}]
// This is the format the InfluxDB node requires to separate fields and tags
msg.payload = [
    {
        voltage: Number(msg.payload.voltage),
        current: Number(msg.payload.current),
        activePower: Number(msg.payload.activePower),
        apparentPower: Number(msg.payload.apparentPower),
        reactivePower: Number(msg.payload.reactivePower),
        powerFactor: Number(msg.payload.powerFactor),
        frequency: Number(msg.payload.frequency),
        energy: Number(msg.payload.energy)
    },
    {
        socket_id: socketId
    }
];

// Set the measurement (table) name in InfluxDB
msg.measurement = "pzem_data";

return msg;

// Extract socket_id and the metric type (relay, fault, timer)
const parts = msg.topic.split('/');
if (parts.length < 3) return null;

const socket_id = parts[1];
const metric = parts[2];

let val = 0;

// Convert states to 1 or 0 for graphing
if (metric === 'relay') {
    if (msg.payload && msg.payload.state) {
        val = (msg.payload.state === 'ON') ? 1 : 0;
    } else return null;
} else if (metric === 'fault') {
    if (msg.payload && msg.payload.fault !== undefined) {
        val = (msg.payload.fault === true || msg.payload.fault === "true") ? 1 : 0;
    } else return null;
} else if (metric === 'timer') {
    if (msg.payload && msg.payload.active !== undefined) {
        val = (msg.payload.active === true || msg.payload.active === "true") ? 1 : 0;
    } else return null;
} else {
    return null;
}

// Construct the InfluxDB payload format
msg.payload = [
    {
        [metric]: val
    },
    {
        socket_id: socket_id
    }
];

msg.measurement = 'socket_state';
return msg;
